import {Styles} from '../utils/utils';
import React, {useEffect, useState} from 'react';
import GitHubIcon from '@mui/icons-material/GitHub';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import EmailIcon from '@mui/icons-material/Email';
import ArticleIcon from '@mui/icons-material/Article';
import { useDispatch } from 'react-redux';
import IconLink from './IconLink';
// import { Link } from 'react-router-dom'

export default function Home(){ 
    let obj = {top: window.innerHeight*0.2}
    let dispatch = useDispatch();
    let [width, setWidth] = useState(window.innerWidth);

    console.log("width: ", window.innerWidth)
    const resizeHandler = () => {
        console.log("called")
        setWidth(window.innerWidth)
    }

    useEffect(() => {
       window.onresize = resizeHandler
      }, [])

return(
        <div style={{alignItems:"normal", border: "none", borderWidth:"10px", borderColor:"red"}}>
            
            <div>
                <h1 style={{...Styles.containerContent, ...obj, ...{fontSize:'500%', border:"none", borderColor:"blue", marginBottom:0}}}>Akshay Sharma</h1><br/>
                <p style={{...Styles.containerContent, ...obj, ...{fontSize:'180%',border: "none", marginTop:0, borderColor:"blue"}}}>Aspiring Software Engineer</p>
                <p style={{...Styles.containerContent, ...obj, ...{fontSize:'110%',border: "none", marginTop:-20, borderColor:"blue"}}}>Distributed Computing | Machine Learning | Computer Graphics</p><br/>
                <p style={{...Styles.containerContent, ...obj, ...{fontSize:'80%',border: "none", marginTop:0, borderColor:"blue"}}}>All graphical effects on this website are made from scratch.<br/> Click anywhere outside the tilting card to draw a hilbert curve!</p><br/><br/>
            </div>
            
            <div className="link" style={{...Styles.containerContent, ...{position:'relative', paddingTop: "200px", paddingLeft:(0.5*width)-225, display:"flex", flexDirection:"row"}}}>
                {/* <a  href={"https://akshaysharma21.github.io/Resume/"}><ArticleIcon sx={{ fontSize: 60, color:"silver" }}/></a>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; */}
                <IconLink text="Resume" link={"https://akshaysharma21.github.io/Resume/"} icon={<ArticleIcon sx={{ fontSize: 65, color:"Grey" }}/>} hoverIcon={<ArticleIcon sx={{ fontSize: 65, color:"White" }}/>}/>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                <IconLink text="GitHub" link={"https://github.com/akshaysharma21"} icon={<GitHubIcon sx={{ fontSize: 65, color:"Grey" }}/>} hoverIcon={<GitHubIcon sx={{ fontSize: 65, color:"White" }}/>}/>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                <IconLink text="LinkedIn" link={"https://www.linkedin.com/in/sharma-akshay21/"} icon={<LinkedInIcon sx={{ fontSize: 65, color:"Grey" }}/>} hoverIcon={<LinkedInIcon sx={{ fontSize: 65, color:"White" }}/>}/>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                <IconLink text="Contact" handleClick = {() => dispatch({type: "toggle"})} link={"#"} icon={<EmailIcon sx={{ fontSize: 65, color:"Grey" }}/>} hoverIcon={<EmailIcon sx={{ fontSize: 65, color:"White" }}/>}/>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;

            </div>
            {/* <div style={{color:'white', position: 'absolute', bottom: 0, left: window.innerWidth*0.8}}>
                <p>&copy;Akshay Sharma, 2021</p>
            </div> */}

        </div>
    )
}